+        // PageBitmap variant
+        let bitmap = KeySummary::PageBitmap(BTreeSet::from([1, 2, 5, 10]));
+        assert!(bitmap.may_overlap(&test_page_key(5)));
+        assert!(!bitmap.may_overlap(&test_page_key(6)));
